{
  "mode": "method",
  "tests": [
    {
      "name": "valid_download_after_submission",
      "input": {
        "member_id": "12345",
        "challenge_id": "67890",
        "submitted": true
      },
      "output": {
        "can_download": true
      },
      "notes": "Validates that a member who has submitted to a challenge can download other submissions."
    },
    {
      "name": "invalid_download_without_submission",
      "input": {
        "member_id": "12345",
        "challenge_id": "67890",
        "submitted": false
      },
      "output": {
        "can_download": false
      },
      "notes": "Ensures that a member who has not submitted cannot download other submissions."
    },
    {
      "name": "multiple_submissions_download",
      "input": {
        "member_id": "12345",
        "challenge_id": "67890",
        "submitted": true
      },
      "output": {
        "can_download": true,
        "downloadable_submissions": ["submission1", "submission2", "submission3"]
      },
      "notes": "Checks that a member can download multiple submissions after submitting."
    },
    {
      "name": "download_attempt_after_challenge_close",
      "input": {
        "member_id": "12345",
        "challenge_id": "67890",
        "submitted": true,
        "challenge_closed": true
      },
      "output": {
        "can_download": true
      },
      "notes": "Validates that a member can still download submissions after the challenge has closed."
    },
    {
      "name": "download_attempt_without_valid_member",
      "input": {
        "member_id": "99999",
        "challenge_id": "67890",
        "submitted": false
      },
      "output": {
        "can_download": false
      },
      "notes": "Tests that an invalid member ID cannot download submissions."
    },
    {
      "name": "download_with_no_submissions_available",
      "input": {
        "member_id": "12345",
        "challenge_id": "67890",
        "submitted": true,
        "available_submissions": []
      },
      "output": {
        "can_download": true,
        "downloadable_submissions": []
      },
      "notes": "Checks that a member can download but finds no submissions available."
    },
    {
      "name": "download_with_invalid_challenge_id",
      "input": {
        "member_id": "12345",
        "challenge_id": "00000",
        "submitted": true
      },
      "output": {
        "can_download": false
      },
      "notes": "Ensures that a member cannot download submissions from an invalid challenge ID."
    },
    {
      "name": "download_after_multiple_submissions",
      "input": {
        "member_id": "12345",
        "challenge_id": "67890",
        "submitted": true,
        "submission_count": 5
      },
      "output": {
        "can_download": true,
        "downloadable_submissions": ["submission1", "submission2", "submission3", "submission4", "submission5"]
      },
      "notes": "Validates that a member with multiple submissions can download all available submissions."
    }
  ],
  "assumptions": "Members must submit to a challenge to access other submissions. Valid member and challenge IDs are required.",
  "notes": "Ensure that the download function adheres to the specified conditions without altering existing functionalities."
}
